/**
 * Articulatory synthesis bisection harness.
 *
 * Run a single stage at a time, listen, then move forward. Each stage adds
 * one transformation to the previous one — when it stops sounding right,
 * the bug is in the most recently added step.
 *
 *   npx tsx open-source/gnosis/scripts/debug-stages.ts <stage>
 *
 * Stages:
 *   0  sine reference        (250 Hz tone — sanity check the audio path)
 *   1  glottal source raw    (steady F0 = 135, no filter, no score)
 *   2  score-driven source   (larynx track on/off + pressure, no filter)
 *   3  static /a/ formants   (stage 2 + fixed cascade tuned to /a/)
 *   4  dynamic formants      (full current engine — same as production)
 */
import * as fs from 'fs';
import * as path from 'path';
import { fileURLToPath } from 'url';
import { execSync } from 'child_process';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const SR = 24000;
const DT = 1 / SR;
const DURATION = 3.4;
const N = Math.floor(DURATION * SR);

// ---- Glottal source ------------------------------------------------------
// Engine's "Rosenberg" was actually opening-only with an instantaneous drop
// to 0 at phase 0.7 (a 0.9-amplitude step every period). That step is the
// dominant noise. Real Rosenberg has three phases: open, close, closed.
// Tp = peak time, Tn = end of closing. Both expressed as fractions of period.
function rosenbergPulse(phase: number, Tp = 0.4, Tn = 0.6): number {
  // Symmetric raised-cosine: zero value AND zero slope at phase 0, Tp boundary
  // continuity, AND zero value+zero slope at Tn. No kinks anywhere → no
  // step in the differentiated (lip-radiated) output.
  if (phase < Tp) return 0.5 * (1 - Math.cos(Math.PI * phase / Tp));
  if (phase < Tn) return 0.5 * (1 + Math.cos(Math.PI * (phase - Tp) / (Tn - Tp)));
  return 0;
}

// Lip radiation modelled as true DC-blocker: y[n] = x[n] - x[n-1] + R*y[n-1].
// Zero at z=1 (kills DC perfectly), pole near z=1 (R≈0.995) so flat above
// ~30 Hz. This matches the +6 dB/octave lip-radiation tilt while removing
// the DC bias from a unipolar glottal flow.
class LipRadiation {
  xPrev = 0;
  yPrev = 0;
  step(x: number, R = 0.995): number {
    const y = x - this.xPrev + R * this.yPrev;
    this.xPrev = x;
    this.yPrev = y;
    return y;
  }
}

// ---- 2-pole resonator (matches engine FormantFilter) ---------------------
class Resonator {
  y1 = 0; y2 = 0;
  a = 0; b = 0; c = 0;
  set(freq: number, bw: number) {
    this.c = -Math.exp(-2 * Math.PI * bw / SR);
    this.b = 2 * Math.exp(-Math.PI * bw / SR) * Math.cos(2 * Math.PI * freq / SR);
    this.a = 1 - this.b - this.c;
  }
  step(x: number): number {
    const y = this.a * x + this.b * this.y1 + this.c * this.y2;
    this.y2 = this.y1;
    this.y1 = y;
    return y;
  }
}

// One-pole LP smoother for control parameters (pressure, voicing).
// Score events are step functions; abrupt jumps in pressure produce edge
// clicks. Smoothing time constant ~8 ms (alpha=0.005 at Fs=24kHz).
class Smoother {
  y = 0;
  step(x: number, alpha = 0.005): number {
    this.y += alpha * (x - this.y);
    return this.y;
  }
}

// Band-pass shaped noise for fricatives. Math.random() gives white noise
// from 0 to Nyquist; a real /f/, /s/, /sh/ fricative has a clear band
// emphasis. Two-pole BP at ~2.5 kHz with BW 2 kHz gives /f/-like coloration
// that removes the sub-bass rumble and upper-band hiss harshness.
class NoiseShaper {
  bp = new Resonator();
  constructor(centerHz = 2500, bwHz = 2000) {
    this.bp.set(centerHz, bwHz);
  }
  step(): number {
    return this.bp.step(Math.random() * 2 - 1);
  }
}

// ---- Score reader --------------------------------------------------------
type LarynxEvent = { pitch: number; pressure: number; tension: number; isVoiced: boolean; startTime: number };
function evalStep<T extends { startTime: number }>(track: T[], t: number, def: T): T {
  let v = def;
  for (const e of track) {
    if (t >= e.startTime) v = e;
    else break;
  }
  return v;
}

// ---- Stages --------------------------------------------------------------
function stage0_sine(): Float32Array {
  const out = new Float32Array(N);
  for (let i = 0; i < N; i++) out[i] = 0.5 * Math.sin(2 * Math.PI * 250 * i * DT);
  return out;
}

function stage1_steadyGlottal(): Float32Array {
  const out = new Float32Array(N);
  const F0 = 135;
  let phase = 0;
  const lip = new LipRadiation();
  for (let i = 0; i < N; i++) {
    phase = (phase + DT * F0) % 1.0;
    out[i] = lip.step(rosenbergPulse(phase) * 0.7);
  }
  return out;
}

function stage2_scoreDrivenSource(score: any): Float32Array {
  const out = new Float32Array(N);
  let phase = 0;
  const lip = new LipRadiation();
  const voiceP = new Smoother();   // smoothed voiced-pressure envelope
  const noiseP = new Smoother();   // smoothed unvoiced-pressure envelope
  const noise = new NoiseShaper();
  const def: LarynxEvent = { pitch: 110, pressure: 0, tension: 0.5, isVoiced: false, startTime: 0 };
  for (let i = 0; i < N; i++) {
    const t = i * DT;
    const lax = evalStep(score.larynx, t, def);
    // Crossfading envelopes: voicing target ramps the voiced level up/down,
    // 1-voicing ramps the unvoiced (fricative) level. Pressure modulates both.
    const vTarget = (lax.isVoiced ? 1 : 0) * lax.pressure;
    const nTarget = (lax.isVoiced ? 0 : 1) * lax.pressure;
    const vGain = voiceP.step(vTarget);
    const nGain = noiseP.step(nTarget);
    const F0 = lax.pitch || 135;
    phase = (phase + DT * F0) % 1.0;
    const voicedSrc = rosenbergPulse(phase) * vGain;
    const noiseSrc  = noise.step() * nGain * 0.3;
    out[i] = lip.step(voicedSrc + noiseSrc);
  }
  return out;
}

function stage3_staticFormants(score: any): Float32Array {
  const out = new Float32Array(N);
  let phase = 0;
  const f = [new Resonator(), new Resonator(), new Resonator(), new Resonator()];
  // Static /a/ vowel formants (US English, adult male-ish)
  f[0].set(700, 80);
  f[1].set(1090, 120);
  f[2].set(2440, 200);
  f[3].set(3400, 250);
  const lip = new LipRadiation();
  const voiceP = new Smoother();
  const noiseP = new Smoother();
  const noise = new NoiseShaper();
  const def: LarynxEvent = { pitch: 110, pressure: 0, tension: 0.5, isVoiced: false, startTime: 0 };
  for (let i = 0; i < N; i++) {
    const t = i * DT;
    const lax = evalStep(score.larynx, t, def);
    const vGain = voiceP.step((lax.isVoiced ? 1 : 0) * lax.pressure);
    const nGain = noiseP.step((lax.isVoiced ? 0 : 1) * lax.pressure);
    const F0 = lax.pitch || 135;
    phase = (phase + DT * F0) % 1.0;
    const src = rosenbergPulse(phase) * vGain + noise.step() * nGain * 0.3;
    let y = src;
    for (const r of f) y = r.step(y);
    out[i] = lip.step(y);
  }
  return out;
}

function stage4_dynamicFormants(score: any): Float32Array {
  const out = new Float32Array(N);
  let phase = 0;
  const f = [new Resonator(), new Resonator(), new Resonator(), new Resonator()];
  // Articulator state (spring-mass-damper, same as engine)
  let tHpos = 0, tHvel = 0, tBpos = 0, tBvel = 0;
  const mass = 0.05, stiff = 10000, damp = 2 * Math.sqrt(0.05 * 10000) * 0.95;
  const lip = new LipRadiation();
  const voiceP = new Smoother();
  const noiseP = new Smoother();
  const noise = new NoiseShaper();
  const def: LarynxEvent = { pitch: 110, pressure: 0, tension: 0.5, isVoiced: false, startTime: 0 };
  for (let i = 0; i < N; i++) {
    const t = i * DT;
    const tH = evalStep(score.tongueHeight, t, { value: 0, startTime: 0 } as any).value;
    const tB = evalStep(score.tongueBackness, t, { value: 0, startTime: 0 } as any).value;
    const lax = evalStep(score.larynx, t, def);
    // Articulator step
    const aH = (-stiff * (tHpos - tH) - damp * tHvel) / mass;
    tHvel += aH * DT; tHpos += tHvel * DT;
    const aB = (-stiff * (tBpos - tB) - damp * tBvel) / mass;
    tBvel += aB * DT; tBpos += tBvel * DT;
    // Engine's formant mapping
    const f1 = Math.max(200, 500 - tHpos * 280);
    const f2 = Math.max(400, 1600 - tBpos * 850 - tHpos * 150);
    f[0].set(f1, 80);
    f[1].set(f2, 120);
    f[2].set(2600, 200);
    f[3].set(3500, 250);

    const vGain = voiceP.step((lax.isVoiced ? 1 : 0) * lax.pressure);
    const nGain = noiseP.step((lax.isVoiced ? 0 : 1) * lax.pressure);
    const F0 = lax.pitch || 135;
    phase = (phase + DT * F0) % 1.0;
    const src = rosenbergPulse(phase) * vGain + noise.step() * nGain * 0.3;
    let y = src;
    for (const r of f) y = r.step(y);
    out[i] = lip.step(y);
  }
  return out;
}

// ---- WAV writer + level report -------------------------------------------
function writeWav(file: string, samples: Float32Array) {
  // Normalize to 0.9 peak so each stage is comparably loud and never clips.
  let peak = 0;
  for (let i = 0; i < samples.length; i++) {
    const a = Math.abs(samples[i]); if (a > peak) peak = a;
  }
  const norm = peak > 0 ? 0.9 / peak : 1.0;
  const i16 = new Int16Array(samples.length);
  let sumAbs = 0, postPeak = 0;
  for (let i = 0; i < samples.length; i++) {
    const v = samples[i] * norm;
    const s = Math.max(-32768, Math.min(32767, Math.round(v * 32767)));
    i16[i] = s;
    const a = Math.abs(s);
    sumAbs += a;
    if (a > postPeak) postPeak = a;
  }
  const buf = Buffer.alloc(44 + i16.length * 2);
  buf.write('RIFF', 0);
  buf.writeUInt32LE(36 + i16.length * 2, 4);
  buf.write('WAVE', 8);
  buf.write('fmt ', 12);
  buf.writeUInt32LE(16, 16);
  buf.writeUInt16LE(1, 20);
  buf.writeUInt16LE(1, 22);
  buf.writeUInt32LE(SR, 24);
  buf.writeUInt32LE(SR * 2, 28);
  buf.writeUInt16LE(2, 32);
  buf.writeUInt16LE(16, 34);
  buf.write('data', 36);
  buf.writeUInt32LE(i16.length * 2, 40);
  for (let i = 0; i < i16.length; i++) buf.writeInt16LE(i16[i], 44 + i * 2);
  fs.writeFileSync(file, buf);
  console.log(`  pre-norm peak: ${peak.toFixed(4)}   norm gain: ${norm.toFixed(4)}`);
  console.log(`  post-norm peak: ${postPeak}/32767  mean |s|: ${(sumAbs / i16.length).toFixed(0)}`);
}

// ---- Main ---------------------------------------------------------------
const stage = parseInt(process.argv[2] ?? '0', 10);
const scorePath = path.join(__dirname, 'gestural-score.json');
const score = JSON.parse(fs.readFileSync(scorePath, 'utf8'));

const labels = [
  'sine 250 Hz reference',
  'steady glottal pulse (F0=135, no filter)',
  'score-driven source (larynx on/off, no filter)',
  'static /a/ formant cascade',
  'dynamic formants (full engine)',
];
console.log(`STAGE ${stage}: ${labels[stage] ?? '?'}`);

let audio: Float32Array;
switch (stage) {
  case 0: audio = stage0_sine(); break;
  case 1: audio = stage1_steadyGlottal(); break;
  case 2: audio = stage2_scoreDrivenSource(score); break;
  case 3: audio = stage3_staticFormants(score); break;
  case 4: audio = stage4_dynamicFormants(score); break;
  default: console.error('Unknown stage'); process.exit(1);
}

const outFile = path.join(__dirname, `debug-stage-${stage}.wav`);
writeWav(outFile, audio);
console.log(`  wrote ${outFile}`);
try { execSync(`afplay ${outFile}`); } catch {}
